def gen(rng, size):
    n = rng.randint(1, min(100, max(1, size)))
    words = []
    for _ in range(n):
        wl = rng.randint(1, 20)
        words.append(''.join(rng.choice('abcde') for _ in range(wl)))
    if rng.random() < 0.5:
        k = rng.randint(1, n)
        s = ''.join(words[:k])
        if rng.random() < 0.3 and s:
            pos = rng.randrange(len(s))
            s = s[:pos] + ('f' if s[pos] != 'f' else 'a') + s[pos+1:]
    else:
        sl = rng.randint(1, 50)
        s = ''.join(rng.choice('abcdef') for _ in range(sl))
    return [s, words]

