var isPrefixString = function(s, words) {
    let i = 0;
    const n = s.length;
    for (const w of words) {
        for (const ch of w) {
            if (i >= n || s[i] !== ch) return false;
            i++;
        }
        if (i === n) return true;
    }
    return i === n;
};
